    // Regression: before `reopen_task`, a task that landed in `in_review` (a
    // drift/needs-human completion) or was manually blocked with no predecessor
    // had no path back to a claimable state — it stranded until a manual DB edit.
    #[test]
    fn reopen_returns_stranded_tasks_to_claimable() {
        let store = store();
        let goal = goal(&store);

        // A manual hold (blocked with no predecessor) reopens and is claimable.
        let held = store
            .create_task(&goal.id, "Held", "done", None, NOW)
            .unwrap();
        assert!(store.block_task(&held.id, None, NOW + 1).unwrap());
        assert!(store.reopen_task(&held.id, NOW + 2).unwrap());
        let reopened = store.get_task(&held.id).unwrap().unwrap();
        assert_eq!(reopened.status, TaskStatus::Open);
        assert!(reopened.blocked_by.is_none());
        assert!(store.claim_task(&held.id, "agent-a", 60, NOW + 3).unwrap());

        // A drift outcome (in_review) reopens too.
        let review = store
            .create_task(&goal.id, "Review", "done", None, NOW)
            .unwrap();
        assert!(store.claim_task(&review.id, "agent-b", 60, NOW).unwrap());
        assert!(store
            .record_conformance_and_transition(
                &review.id,
                "agent-b",
                ConformanceAudit {
                    evidence_schema_version: 1,
                    evidence: "{}",
                    verdict: Verdict::Drift,
                    findings: "",
                },
                TaskStatus::InReview,
                NOW,
            )
            .unwrap());
        assert_eq!(
            store.get_task(&review.id).unwrap().unwrap().status,
            TaskStatus::InReview
        );
        assert!(store.reopen_task(&review.id, NOW + 1).unwrap());
        assert_eq!(
            store.get_task(&review.id).unwrap().unwrap().status,
            TaskStatus::Open
        );
    }

    #[test]
    fn reopen_refuses_gated_active_and_terminal_tasks() {
        let store = store();
        let goal = goal(&store);

        // A handoff-gated task must not be reopened around its predecessor.
        let predecessor = store
            .create_task(&goal.id, "Pred", "done", None, NOW)
            .unwrap();
        let gated = store
            .create_task_after(
                &goal.id,
                "Gated",
                "done",
                None,
                Some(predecessor.id.clone()),
                NOW + 1,
            )
            .unwrap();
        assert_eq!(gated.status, TaskStatus::Blocked);
        assert!(store
            .reopen_task(&gated.id, NOW + 2)
            .unwrap_err()
            .to_string()
            .contains("gated by predecessor"));

        // An open task is not stranded; a claimed task must be released instead.
        let open = store
            .create_task(&goal.id, "Open", "done", None, NOW)
            .unwrap();
        assert!(store
            .reopen_task(&open.id, NOW + 1)
            .unwrap_err()
            .to_string()
            .contains("cannot be reopened"));
        assert!(store.claim_task(&open.id, "agent-a", 60, NOW + 2).unwrap());
        assert!(store
            .reopen_task(&open.id, NOW + 3)
            .unwrap_err()
            .to_string()
            .contains("cannot be reopened"));

        // Terminal work stays terminal.
        let done = store
            .create_task(&goal.id, "Done", "done", None, NOW)
            .unwrap();
        complete_aligned(&store, &done.id, "agent-c", NOW);
        assert!(store
            .reopen_task(&done.id, NOW + 1)
            .unwrap_err()
            .to_string()
            .contains("cannot be reopened"));
    }

    // Regression: `TaskStatus::Abandoned` was defined but unreachable — no verb
    // produced it, so a task that should never be done (e.g. a mis-filed policy
    // task) could not be retired short of wiping the database.
    #[test]
    fn abandon_retires_nonterminal_tasks_and_refuses_claimed_and_terminal() {
        let store = store();
        let goal = goal(&store);

        // An open task (e.g. a zombie policy task) retires to terminal abandoned.
        let open = store
            .create_task(&goal.id, "Zombie", "done", None, NOW)
            .unwrap();
        assert!(store.abandon_task(&open.id, NOW + 1).unwrap());
        let retired = store.get_task(&open.id).unwrap().unwrap();
        assert_eq!(retired.status, TaskStatus::Abandoned);
        assert!(retired.owner.is_none());
        // Abandoned is terminal: not claimable, not re-abandonable.
        assert!(!store.claim_task(&open.id, "agent-a", 60, NOW + 2).unwrap());
        assert!(store
            .abandon_task(&open.id, NOW + 3)
            .unwrap_err()
            .to_string()
            .contains("cannot be abandoned"));

        // A stranded manual-hold (blocked, no predecessor) can also be retired.
        let held = store
            .create_task(&goal.id, "Held", "done", None, NOW)
            .unwrap();
        assert!(store.block_task(&held.id, None, NOW + 1).unwrap());
        assert!(store.abandon_task(&held.id, NOW + 2).unwrap());
        assert_eq!(
            store.get_task(&held.id).unwrap().unwrap().status,
            TaskStatus::Abandoned
        );

        // A live claim must be released first, never silently retired.
        let claimed = store
            .create_task(&goal.id, "Claimed", "done", None, NOW)
            .unwrap();
        assert!(store.claim_task(&claimed.id, "agent-b", 60, NOW).unwrap());
        assert!(store
            .abandon_task(&claimed.id, NOW + 1)
            .unwrap_err()
            .to_string()
            .contains("release it before abandoning"));

        // Terminal (done) work stays terminal.
        let done = store
            .create_task(&goal.id, "Done", "done", None, NOW)
            .unwrap();
        complete_aligned(&store, &done.id, "agent-c", NOW);
        assert!(store
            .abandon_task(&done.id, NOW + 1)
            .unwrap_err()
            .to_string()
            .contains("cannot be abandoned"));
    }

